var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"얘들아, 그거 들었어?","JPN":"みんな、聞いた？","ENG":"Hey, did you hear?","TWN":"大家聽說了嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"카운터즈 레거시 말인데, 이번에 엄청난 업데이트를 했대!\xA0\xA0","JPN":"カウンターズ・レガシー、今回大型アップデートがあったんだって！\xA0\xA0","ENG":"It's about Counters Legacy–they just had a huge update!\xA0\xA0","TWN":"關於制裁者的遺產，這次進行了大規模的更新！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"자세한 건 선생님이 설명해 주시겠지만, 그때까지 참을 수 없었지 뭐야.","JPN":"詳しいことは先生が説明してくれると思うけど、それまで我慢できなくて。","ENG":"Our teacher will explain it in detail later, but I just couldn't wait.","TWN":"詳細情況老師會解釋，但我等不及了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그 업데이트가 뭔지부터 설명해 줘야 하는 거 아냐?","JPN":"そのアップデートの内容が何なのか、そっちが先なんじゃないの？","ENG":"Shouldn't you first tell us what the update is about?","TWN":"你是不是應該先解釋一下那個更新是什麼？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그건 지금부터 제가 설명하죠.","JPN":"それは今から私が説明します。","ENG":"I can do that.","TWN":"那接下來由我來說明吧。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"여러분, 드디어 때가 됐습니다.","JPN":"皆さん。ついに、この時がきました。","ENG":"Everyone, the time has finally come.","TWN":"各位，終於到了這個時候。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐, 뭐야……? 갑자기 띨빵해 보이는 안경이나 쓰고.","JPN":"な、何よ……その間抜けなメガネ。","ENG":"H-huh...? Why's she wearing those stupid-looking glasses?","TWN":"怎，怎麼回事……？突然戴上了看起來很呆的眼鏡。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"선생님께서 저 안경을 쓰셨다는 건 엄청 진지한 상태라는 뜻일 거야.","JPN":"先生があのメガネをかけてるってことは、かなり真剣モードってことだよ。","ENG":"Wearing those glasses must mean that she's super serious.","TWN":"老師戴上那副眼鏡，說明他現在非常認真。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"카운터즈 레거시의 그라운드 원 서버가 오늘 오픈했어요.","JPN":"カウンターズ・レガシーのグラウンド・ワンサーバーが本日オープンしました。","ENG":"Counters Legacy's Ground One server just launched today.","TWN":"制裁者的遺產的G1伺服器今天開放了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"현재 그라운드 원의 접속률은 계속해서 증가 중입니다. 이 성과는 역대 최대에요!","JPN":"グラウンド・ワンからのアクセス率は、どんどん上昇中です。これは歴代最高の成果です！","ENG":"The number of active users in Ground One is increasing, and it's our greatest achievement yet!","TWN":"目前G1的登入人數持續增加，這是有史以來最大的成果！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"참여하고 싶은 학생들은 언제든지 저에게 말씀해 주시면 됩니다.","JPN":"参加したい生徒は、いつでも私に声をかけてくださいね。","ENG":"Any students who wish to join can let me know at anytime.","TWN":"想要參加的學生可以隨時告訴我。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"드디어 때가 됐군! 이 나이엘 블루스틸의 이름을 알릴 때가 말이야.","JPN":"やっとこの時が来たわね！　このナイエル・ブルースチールの名を馳せる時が！","ENG":"It's finally time! For me, Naielle Bluesteel, to make my name known to the public!","TWN":"終於到了這個時候了！是時候讓世界知道奈爾·布魯斯提爾這個名字了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L21_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"자리에 앉아요 학생. 아직 설명할 게 남았으니까요.","JPN":"席についてください。まだ説明は終わってませんよ。","ENG":"Please sit down. I still have more to share.","TWN":"坐下吧，同學。我還有一些事情要解釋。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그라운드 원 서버를 오픈하면서 랭킹 시스템도 추가됐습니다.","JPN":"グラウンド・ワンサーバーのオープンに伴い、ランキングシステムが追加されました。","ENG":"With the launch of the Ground One server, a ranking system has also been added.","TWN":"隨著G1伺服器的開放，排名系統也已添加。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"여러분들의 카운터 등급과, 카운터즈 레거시에서 활약을 통해 정해질 거예요.","JPN":"ランキングは皆さんのカウンターランクと、カウンターズ・レガシーでの活躍を元に決まります。","ENG":"Your ranks will be determined by your Counter Grade and achievements in Counters Legacy.","TWN":"將根據你們的制裁者等級，和在制裁者的遺產中的表現來決定。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"카운터즈 레거시의 탐험률과 퀘스트 클리어 횟수가 랭킹에 반영될 예정이죠.","JPN":"カウンターズ・レガシーの探索率やクエストクリア回数がランキングに反映される予定です。","ENG":"Your rank will reflect your exploration rate and number of quests cleared in Counters Legacy.","TWN":"制裁者的遺產的探索率和任務完成次數將會呈現在排名中。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"만약 여러분들이 랭커가 되면 태스크포스와 관리국의 눈에 들게 될 겁니다.","JPN":"皆さんが上位ランカーになれば、タスクフォースと管理局の目に留まることになるでしょう。","ENG":"If you manage to become one of the top rankers, you will be noticed by TASKFORCEs and the Administration.","TWN":"如果你們是名列前茅的人，就會引起特遣勢力和管理局的注意。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"랭커라고? 하하, 그런 건 이미 따놓은 당상이지.","JPN":"ランカーですって？　そんなの朝飯前よ。","ENG":"A top ranker? Haha, I'm basically already on that list.","TWN":"名列前茅？哈哈，我不是早就名列前茅了嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"설령 태스크포스 출신이라고 해도, 이 몸 앞에서 주름잡는 꼴이라구. \xA0\xA0","JPN":"たとえタスクフォース出身でも、私の前ではグーの音も出せなくなるんだから。\xA0\xA0 ","ENG":"Even if the others are already in TASKFORCEs, they're nothing compared to me.\xA0\xA0","TWN":"即使是特遣勢力出身，也別想在我面前囂張。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"으앗, 뭐, 뭐야?!","JPN":"うわっ、な、なんなの！？","ENG":"Whoa, h-huh?!","TWN":"啊，什，什麼？！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그라운드 원의 카운터들을 무시하면 큰코다칠 겁니다.","JPN":"グラウンド・ワンのカウンターたちを甘く見ると大変な目に遭いますよ。","ENG":"Don't underestimate the Counters of Ground One.","TWN":"如果無視G1的那些制裁者，會吃大虧的。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"당신이 이곳에선 엘리트일지라도 밖에서는 철없는 귀염둥이일 뿐이니까요.","JPN":"あなたはここではエリートかもしれないけど、外ではただのかわいい子どもに過ぎませんから。","ENG":"You may be an elite here at the Academy, but out there, you're just an immature cutie.","TWN":"即使你在這裡是精英，在外面也不過是個不懂事的小朋友而已。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"귀, 귀염둥이?!","JPN":"こ、子ども！？","ENG":"C-cutie?!","TWN":"小朋友？！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"사람 깔보기는! 내가 그깟 놈들한테 지기라도 할까 봐?","JPN":"見くびらないでよね！　私があんな奴らに負けるとでも思ってるの？","ENG":"I'm insulted! Do you really think I'd lose to chumps like them?","TWN":"瞧不起人？！你以為我會輸給那些傢伙嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"너 옛날에도 편입생들한테 밀렸었잖아.","JPN":"あなた、前にも編入生たちに負けたじゃない。","ENG":"You did lose to the transfer students in the past.","TWN":"你以前也被轉學生輾壓過吧。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"시끄러! 지금의 난 달라!","JPN":"うるさい！　今の私は違うの！","ENG":"Shut it! I'm stronger now!","TWN":"吵死了！現在的我不一樣了！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"난 지금 바로 접속하겠어! 당장이라도 내 실력을 보여줘야지!","JPN":"今すぐアクセスするわ！　私の実力を見せつけてやる！","ENG":"I'm going to log in right now! I'll show them how tough I am!","TWN":"我現在就要登入！馬上展示我的實力！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"너희 둘은 어떻게 할 생각이야?","JPN":"あんたたちはどうするつもり？","ENG":"What are you two going to do?","TWN":"你們兩個打算怎麼辦？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"음…… 글쎄?","JPN":"さあ……","ENG":"Um... I'm not sure.","TWN":"嗯……該怎麼辦呢？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"카운터즈 레거시에서 마술 공연을 펼쳐보는 건 어떠세요?","JPN":"カウンターズ・レガシーでマジックショーをやってみるのはどうですか？","ENG":"How about putting on a magic show in Counters Legacy?","TWN":"在制裁者的遺產中展示魔術表演怎麼樣？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"온라인이니까 접근성도 좋고, 도전해 볼만할 것 같은데.","JPN":"オンラインだから接近性もいいし、やってみる価値はあると思いますけど。","ENG":"Since it's online, it'll be easily accessible and worth a shot.","TWN":"因為是線上的系統，所以很方便，值得挑戰一下。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"유저들을 지켜보는 건 관리국과 태스크포스뿐만이 아니에요.","JPN":"ユーザーを観察しているのは管理局とタスクフォースだけじゃありません。","ENG":"It's not just TASKFORCEs and the Administration who are observing the users.","TWN":"注視著玩家的不僅僅是管理局和特遣勢力。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"잘하면…… 미카 학생의 꿈을 이뤄줄 스폰서와의 만남이 있을 수도 있겠죠.","JPN":"上手くいけば……ミカさんの夢を叶えてくれるスポンサーに出会えるかもしれません。","ENG":"Best-case scenario... you might meet a sponsor who will help you achieve your dream, Mika.","TWN":"如果運氣好的話……也許會遇到能實現米卡同學夢想的贊助商呢。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"저, 정말요……?!","JPN":"ほ、本当ですか……！？","ENG":"R-really...?!","TWN":"真，真的嗎……？！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하, 카운터면서 아직도 그런 소박한 꿈이나 꾸는 거야?","JPN":"はっ！　カウンターのくせに、まだそんな平凡な夢見てるの？","ENG":"*Scoff* Do you still have such a small dream? You're a Counter!","TWN":"哈？身為制裁者還在做那麼樸實的夢嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"흥! 이젠 그런 도발에 넘어가지 않아. 난 내 꿈에 확신이 있어!","JPN":"ふん！　もうそんな挑発には乗らないよ！　あたしは自分の夢に確信があるんだから！","ENG":"Hmph! I'm not letting you get into my head anymore. I have confidence in my dream!","TWN":"哼！現在我不會被這種挑釁激怒了。我對我的夢想充滿信心！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"시엘 너는?","JPN":"シエルちゃんは？","ENG":"What about you, Ciel?","TWN":"希爾，你呢？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"사실 소인은 선도부 일에 지장이 갈까 염려된다오.","JPN":"実は、風紀委員の仕事に支障が出ないか心配でして。","ENG":"In truth, I am concerned that it will interfere with my duties as Student Guide.","TWN":"其實在下擔心會影響到風紀股長的工作。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"옌 역시 아카데미 수업을 제외하곤 참여하지 않겠다는 포부를 보였소.","JPN":"イェンもアカデミーの授業以外には参加しないという意思を表明していますし。","ENG":"Yen has also declared that she will not be participating with the exemption for Academy classes.","TWN":"嫣杏也表示，除了學院課程外，不會參與其他活動。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하핫, 너희들이 빠져준다면야 나야 좋지.","JPN":"ふふん、あんたたちが抜けるのは私としては大歓迎よ。","ENG":"Haha. Less competition for me to worry about, then.","TWN":"哈哈，如果你們都不參加的話，我當然樂意參加了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그럼 뭣들하고 있어? 나머진 모두 같은 마음 아냐?","JPN":"それじゃ、他のみんなはどうするの？　同じ気持ちなんじゃないの？","ENG":"What are we standing around for? Everyone else is in, right?","TWN":"那還等什麼？其他人不也是一樣的想法嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STUDENT_LEGACY_NULL_EXTRA","text":{"KOREA":"하하! 나이엘 혼자 활약하게 둘 순 없지!","JPN":"はは！　ナイエルだけ活躍させるわけにはいかないよね！","ENG":"Haha! I can't let Naielle hog the spotlight!","TWN":"哈哈！不能讓奈爾一個人出風頭！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STUDENT_LEGACY_NULL_EXTRA","text":{"KOREA":"좋았어! 우리도 해 보는 거야!","JPN":"よおし！　私たちもやってみよう！","ENG":"All right! Let's do this!","TWN":"好的！我們也來試試吧！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"훌륭해요! 이 열기를 교실에서 식히게 둘 순 없겠어요!","JPN":"素晴らしいです！　この熱気を教室で冷ましてしまうわけにはいきませんね！","ENG":"Excellent! I can't let the excitement of this classroom simmer down!","TWN":"太棒了！不能讓這股熱情在教室裡冷卻下來！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"접속하실 분들은 지금부터 절 따라오세요!\xA0\xA0","JPN":"アクセスする方はみんな、私について来てください！\xA0\xA0","ENG":"Everyone who wants to log in should follow me right now!\xA0\xA0","TWN":"要參加的各位，現在跟我來吧！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"}]`);export{e as default};